     5→// -----------------------------------------------------------------------------
     6→// WindowedSentimentAggregator
     7→// -----------------------------------------------------------------------------
     8→// Listens to low-level “sentiment-prediction” events coming from the real-time
     9→// feature pipeline, performs sliding-window aggregation per community, and
    10→// republishes window-level aggregates to a downstream Kafka topic so that
    11→// dashboards, alerting rules, and adaptive-content engines can react in near
    12→// real time.
    13→//
    14→// ─── Tech Stack ────────────────────────────────────────────────────────────────
    15→// • KafkaJS             – stream transport (consumer / producer)
    16→// • RxJS                – reactive in-process pipeline
    17→// • Axios               – HTTP client for model-monitoring callbacks
    18→// • uuid                – correlation / id generation
    19→// -----------------------------------------------------------------------------
    20→// Author: AgoraPulse Core Engineering
    21→// License: Apache-2.0
    22→// -----------------------------------------------------------------------------
    23→
    24→/* eslint-disable no-console */
    25→
    26→'use strict';
    27→
    28→const { Kafka, logLevel } = require('kafkajs');
    29→const {
    30→  Subject,
    31→  BehaviorSubject,
    32→  timer,
    33→  of,
    34→} = require('rxjs');
    35→const {
    36→  groupBy,
    37→  bufferTime,
    38→  mergeMap,
    39→  map,
    40→  filter,
    41→  tap,
    42→  catchError,
    43→  retryWhen,
    44→  delayWhen,
    45→} = require('rxjs/operators');
    46→const axios = require('axios').default;
    47→const { v4: uuidv4 } = require('uuid');
    48→
    49→/* -------------------------------------------------------------------------- */
    50→/*                               Config Defaults                              */
    51→/* -------------------------------------------------------------------------- */
    52→
    53→/**
    54→ * Default configuration.  Override by passing a partial config object when
    55→ * instantiating the aggregator or by using environment variables.
    56→ */
    57→const DEFAULT_CONFIG = Object.freeze({
    58→  kafka: {
    59→    brokers: process.env.KAFKA_BROKERS?.split(',') || ['localhost:9092'],
    60→    clientId: process.env.KAFKA_CLIENT_ID || 'agorapulse-sentiment-aggregator',
    61→    ssl: process.env.KAFKA_SSL === 'true',
    62→  },
    63→  topics: {
    64→    source: process.env.KAFKA_TOPIC_SOURCE || 'social.predictions.sentiment',
    65→    sink: process.env.KAFKA_TOPIC_SINK || 'social.aggregates.sentiment.window',
    66→  },
    67→  window: {
    68→    /* Sliding time window size in milliseconds */
    69→    durationMs: Number(process.env.AGG_WINDOW_MS) || 30_000,
    70→    /* Maximum number of items kept inside a single buffer before it flushes */
    71→    maxBufferSize: Number(process.env.AGG_WINDOW_MAX_SIZE) || 5_000,
    72→  },
    73→  monitoring: {
    74→    /* HTTP Endpoint to push anomaly notifications to model-monitoring service */
    75→    endpoint:
    76→      process.env.MODEL_MON_MONITORING_ENDPOINT ||
    77→      'http://localhost:7000/api/v1/alerts',
    78→    /* If `avgSentiment` goes below this threshold an alert is emitted */
    79→    negativeSentimentThreshold:
    80→      Number(process.env.NEG_SENTIMENT_THRESHOLD) || -0.6,
    81→  },
    82→  retry: {
    83→    /* Exponential back-off base (ms) for transient failures */
    84→    baseDelayMs: 1000,
    85→    /* Maximum amount of retries before giving up */
    86→    maxRetries: 5,
    87→  },
    88→});
