    90→/* -------------------------------------------------------------------------- */
    91→/*                             Utility / Type Guards                          */
    92→/* -------------------------------------------------------------------------- */
    93→
    94→/**
    95→ * Parses a Kafka message value (assumed JSON) into a plain object.
    96→ * @param {import('kafkajs').KafkaMessage} msg
    97→ * @returns {{communityId: string, sentiment: number, timestamp: number, ...}}
    98→ */
    99→function parseMessage(msg) {
   100→  try {
   101→    // KafkaJS delivers the message value as a Buffer
   102→    return JSON.parse(msg.value.toString('utf8'));
   103→  } catch (err) {
   104→    console.error(`[Aggregator] Failed to parse message:`, err);
   105→    return null;
   106→  }
   107→}
   108→
   109→/**
   110→ * Calculates windowed sentiment statistics.
   111→ * @param {Array<{sentiment: number, timestamp: number}>} events
   112→ * @returns {{count: number, avgSentiment: number, min: number, max: number}}
   113→ */
   114→function calculateStats(events) {
   115→  const count = events.length;
   116→  if (count === 0) {
   117→    return { count: 0, avgSentiment: 0, min: 0, max: 0 };
   118→  }
   119→  let sum = 0;
   120→  let min = Infinity;
   121→  let max = -Infinity;
   122→  for (const { sentiment } of events) {
   123→    sum += sentiment;
   124→    if (sentiment < min) min = sentiment;
   125→    if (sentiment > max) max = sentiment;
   126→  }
   127→  return {
   128→    count,
   129→    avgSentiment: sum / count,
   130→    min,
   131→    max,
   132→  };
   133→}
