   135→/* -------------------------------------------------------------------------- */
   136→/*                          WindowedSentimentAggregator                       */
   137→/* -------------------------------------------------------------------------- */
   138→
   139→class WindowedSentimentAggregator {
   140→  /**
   141→   * @param {Partial<typeof DEFAULT_CONFIG>} [customConfig]
   142→   */
   143→  constructor(customConfig = {}) {
   144→    this.config = deepMerge(DEFAULT_CONFIG, customConfig);
   145→
   146→    // Kafka client / producer / consumer
   147→    this.kafka = new Kafka({
   148→      clientId: this.config.kafka.clientId,
   149→      brokers: this.config.kafka.brokers,
   150→      ssl: this.config.kafka.ssl,
   151→      logLevel: logLevel.NOTHING,
   152→    });
   153→
   154→    this.producer = this.kafka.producer();
   155→    this.consumer = this.kafka.consumer({ groupId: this.config.kafka.clientId });
   156→
   157→    // RxJS subject as the bridge between Kafka messages and reactive ops
   158→    this._event$ = new Subject();
   159→
   160→    // Stop / shutdown coordination
   161→    this._isShuttingDown$ = new BehaviorSubject(false);
   162→  }
   163→
   164→  /* -------------------------------------------------------------------- */
   165→  /*                              Lifecycle                               */
   166→  /* -------------------------------------------------------------------- */
   167→
   168→  /**
   169→   * Initializes Kafka connections and spins up the reactive pipeline.
   170→   */
   171→  async start() {
   172→    console.info('[Aggregator] Starting WindowedSentimentAggregator …');
   173→
   174→    await Promise.all([this.producer.connect(), this.consumer.connect()]);
   175→
   176→    await this.consumer.subscribe({
   177→      topic: this.config.topics.source,
   178→      fromBeginning: false,
   179→    });
   180→
   181→    // Forward valid messages to the Subject
   182→    this.consumer.run({
   183→      eachMessage: async ({ message }) => {
   184→        const payload = parseMessage(message);
   185→        if (payload && payload.communityId && typeof payload.sentiment === 'number') {
   186→          this._event$.next(payload);
   187→        }
   188→        // Invalid messages are silently ignored; statistics would capture them separately
   189→      },
   190→    });
   191→
   192→    // Build reactive graph
   193→    this._subscription = this._buildReactivePipeline();
   194→
   195→    // Graceful shutdown signals
   196→    process.once('SIGINT', () => this.stop());
   197→    process.once('SIGTERM', () => this.stop());
   198→  }
   199→
   200→  /**
   201→   * Tears down Kafka resources and reactive streams.
   202→   */
   203→  async stop() {
   204→    // Ensure idempotency
   205→    if (this._isShuttingDown$.value) return;
   206→    this._isShuttingDown$.next(true);
   207→
   208→    console.info('[Aggregator] Shutting down WindowedSentimentAggregator …');
   209→
   210→    // Wait for in-flight buffers to flush
   211→    await this._subscription?.unsubscribe?.();
   212→
   213→    await Promise.all([
   214→      this.consumer.disconnect().catch(() => undefined),
   215→      this.producer.disconnect().catch(() => undefined),
   216→    ]);
   217→
   218→    console.info('[Aggregator] Graceful shutdown complete.');
   219→  }
   220→
   221→  /* -------------------------------------------------------------------- */
   222→  /*                           Reactive Pipeline                          */
   223→  /* -------------------------------------------------------------------- */
   224→
   225→  /**
   226→   * Creates the RxJS pipeline that does:
   227→   *   1. groupBy communityId
   228→   *   2. bufferTime → window aggregations
   229→   *   3. calculate statistics
   230→   *   4. forward to sink Kafka topic
   231→   *   5. trigger monitoring on negative spikes
   232→   *
   233→   * @returns {import('rxjs').Subscription}
   234→   */
   235→  _buildReactivePipeline() {
   236→    const {
   237→      window: { durationMs, maxBufferSize },
   238→      monitoring: { negativeSentimentThreshold },
   239→    } = this.config;
   240→
   241→    return this._event$
   242→      .pipe(
   243→        // ------------------------------------
   244→        // Split stream per community
   245→        // ------------------------------------
   246→        groupBy((event) => event.communityId),
   247→
   248→        // ------------------------------------
   249→        // Per-community sliding window
   250→        // ------------------------------------
   251→        mergeMap((community$) =>
   252→          community$.pipe(
   253→            bufferTime(durationMs, undefined, maxBufferSize),
   254→            filter((events) => events.length > 0),
   255→            map((events) => ({
   256→              communityId: community$.key,
   257→              windowStart: events[0].timestamp,
   258→              windowEnd: events[events.length - 1].timestamp,
   259→              stats: calculateStats(events),
   260→            }))
   261→          )
   262→        ),
   263→
   264→        // ------------------------------------
   265→        // Post-processing & side effects
   266→        // ------------------------------------
   267→        tap((aggregate) => this._publishAggregate(aggregate)),
   268→        mergeMap((aggregate) => this._maybeSendMonitoringAlert(aggregate, negativeSentimentThreshold)),
   269→
   270→        // ------------------------------------
   271→        // Error handling / resiliency
   272→        // ------------------------------------
   273→        catchError((err, caught$) => {
   274→          console.error('[Aggregator] Stream error encountered:', err);
   275→          // Let the stream continue (swallow error) – or one could return of()
   276→          return caught$;
   277→        })
   278→      )
   279→      .subscribe();
   280→  }
   281→
   282→  /* -------------------------------------------------------------------- */
   283→  /*                          Side-Effect Functions                       */
   284→  /* -------------------------------------------------------------------- */
   285→
   286→  /**
   287→   * Publishes the computed aggregate to a Kafka topic.
   288→   * @param {{
   289→   *  communityId: string,
   290→   *  windowStart: number,
   291→   *  windowEnd: number,
   292→   *  stats: {count:number, avgSentiment:number, min:number, max:number}
   293→   * }} aggregate
   294→   */
   295→  async _publishAggregate(aggregate) {
   296→    const payload = {
   297→      ...aggregate,
   298→      aggregateId: uuidv4(),
   299→      createdAt: Date.now(),
   300→    };
   301→
   302→    try {
   303→      await this.producer.send({
   304→        topic: this.config.topics.sink,
   305→        messages: [
   306→          {
   307→            key: aggregate.communityId,
   308→            value: JSON.stringify(payload),
   309→          },
   310→        ],
   311→      });
   312→
   313→      console.debug(
   314→        `[Aggregator] Sent aggregate for community=${aggregate.communityId} ` +
   315→          `(count=${aggregate.stats.count}, avg=${aggregate.stats.avgSentiment.toFixed(3)})`
   316→      );
   317→    } catch (err) {
   318→      console.error('[Aggregator] Failed to publish aggregate:', err);
   319→    }
   320→  }
   321→
   322→  /**
   323→   * Sends a monitoring alert if negative sentiment exceeds threshold.
   324→   * Returns a cold Observable so that mergeMap can subscribe to it.
   325→   *
   326→   * @param {{communityId:string, stats:{avgSentiment:number}}} aggregate
   327→   * @param {number} threshold
   328→   */
   329→  _maybeSendMonitoringAlert(aggregate, threshold) {
   330→    if (aggregate.stats.avgSentiment >= threshold) {
   331→      return of(null); // No alert required
   332→    }
   333→
   334→    const alertPayload = {
   335→      id: uuidv4(),
   336→      type: 'NEGATIVE_SENTIMENT_SPIKE',
   337→      timestamp: Date.now(),
   338→      communityId: aggregate.communityId,
   339→      aggregatedWindow: {
   340→        start: aggregate.windowStart,
   341→        end: aggregate.windowEnd,
   342→      },
   343→      metrics: aggregate.stats,
   344→      threshold,
   345→      // Additional metadata for correlation
   346→      source: 'WindowedSentimentAggregator',
   347→      environment: process.env.NODE_ENV || 'development',
   348→    };
   349→
   350→    console.warn(
   351→      `[Aggregator] Negative sentiment alert for community=${aggregate.communityId} ` +
   352→        `(avg=${aggregate.stats.avgSentiment.toFixed(3)} < ${threshold})`
   353→    );
   354→
   355→    // Return an Observable to integrate nicely with RxJS error handling
   356→    return of(alertPayload).pipe(
   357→      mergeMap((payload) =>
   358→        axios
   359→          .post(this.config.monitoring.endpoint, payload, {
   360→            timeout: 5_000,
   361→          })
   362→          .then(() => null) // Map to null to keep stream type consistent
   363→      ),
   364→      retryWithBackoff(this.config.retry),
   365→      catchError((err) => {
   366→        console.error('[Aggregator] Failed to send monitoring alert:', err);
   367→        return of(null); // Swallow error so the main stream remains alive
   368→      })
   369→    );
   370→  }
   371→}
   372→
   373→/* -------------------------------------------------------------------------- */
   374→/*                              Helper Functions                              */
   375→/* -------------------------------------------------------------------------- */
   376→
   377→/**
   378→ * Performs a deep merge of `source` into `target`. Arrays & primitives in
   379→ * `source` fully overwrite `target`'s values to avoid unexpected semantics.
   380→ *
   381→ * @param {object} target
   382→ * @param {object} source
   383→ * @returns {object} new merged object
   384→ */
   385→function deepMerge(target, source) {
   386→  // Simple implementation sufficient for config objects
   387→  if (!source) return { ...target };
   388→  const output = { ...target };
   389→  for (const [key, value] of Object.entries(source)) {
   390→    if (value && typeof value === 'object' && !Array.isArray(value)) {
   391→      output[key] = deepMerge(target[key] || {}, value);
   392→    } else {
   393→      output[key] = value;
   394→    }
   395→  }
   396→  return output;
   397→}
   398→
   399→/**
   400→ * Factory for RxJS `retryWhen` with exponential back-off.
   401→ *
   402→ * @param {{baseDelayMs:number, maxRetries:number}} cfg
   403→ */
   404→function retryWithBackoff(cfg) {
   405→  const { baseDelayMs, maxRetries } = cfg;
   406→  return retryWhen((errors) =>
   407→    errors.pipe(
   408→      mergeMap((error, i) => {
   409→        const attempt = i + 1;
   410→        if (attempt > maxRetries) {
   411→          console.error(
   412→            `[Aggregator] Max retries (${maxRetries}) exceeded. Giving up.`,
   413→            error
   414→          );
   415→          throw error;
   416→        }
   417→        const delayMs = baseDelayMs * 2 ** i;
   418→        console.warn(
   419→          `[Aggregator] Attempt ${attempt} failed – retrying in ${delayMs}ms`
   420→        );
   421→        return timer(delayMs);
   422→      })
   423→    )
   424→  );
   425→}
