   428→/*                               Entry-point                                 */
   429→/* -------------------------------------------------------------------------- */
   430→
   431→if (require.main === module) {
   432→  // Launch directly if executed as a node process
   433→  const aggregator = new WindowedSentimentAggregator();
   434→
   435→  aggregator
   436→    .start()
