   438→      console.info('[Aggregator] WindowedSentimentAggregator is up & running.')
   439→    )
   440→    .catch((err) => {
   441→      console.error('[Aggregator] Startup failed:', err);
   442→      process.exitCode = 1;
   443→    });
   444→}
