    99→ * P(Ŷ = 1 | A = unprotected) – P(Ŷ = 1 | A = protected)
   100→ */
   101→function statisticalParity(events, protectedPredicate) {
   102→    const protectedGrp = events.filter(protectedPredicate);
   103→    const unprotectedGrp = events.filter((e) => !protectedPredicate(e));
   104→
   105→    const rate = (arr) =>
   106→        arr.length === 0
   107→            ? 0
   108→            : arr.reduce((acc, e) => acc + e.prediction, 0) / arr.length;
   109→
   110→    return rate(unprotectedGrp) - rate(protectedGrp);
   111→}
