   119→    const positives = events.filter((e) => e.label === 1);
   120→
   121→    const protectedPositives = positives.filter(protectedPredicate);
   122→    const unprotectedPositives = positives.filter((e) => !protectedPredicate(e));
   123→
   124→    const tpr = (arr) =>
   125→        arr.length === 0
   126→            ? 0
   127→            : arr.reduce((acc, e) => acc + (e.prediction === 1 ? 1 : 0), 0) /
   128→              arr.length;
   129→
   130→    return tpr(unprotectedPositives) - tpr(protectedPositives);
