   137→ *
   138→ * @param {number[]} baselineCounts
   139→ * @param {number[]} currentCounts
   140→ */
   141→function populationStabilityIndex(baselineCounts, currentCounts) {
   142→    const totalBaseline = _.sum(baselineCounts);
   143→    const totalCurrent = _.sum(currentCounts);
   144→
   145→    if (totalBaseline === 0 || totalCurrent === 0) return 0;
   146→
   147→    return baselineCounts.reduce((psi, baseCount, idx) => {
   148→        const currCount = currentCounts[idx];
   149→        const basePct = baseCount / totalBaseline || 1e-6;
   150→        const currPct = currCount / totalCurrent || 1e-6;
   151→        return psi + (currPct - basePct) * Math.log(currPct / basePct);
