     2→/**
     3→ * src/module_21.js
     4→ *
     5→ * High-throughput domain-event ingestion and real-time feature-engineering pipeline
     6→ * for AgoraPulse.  Bridges a Kafka topic => RxJS observable => pluggable
     7→ * Strategy-based feature extractor => downstream Kafka sink.
     8→ *
     9→ * The module purposefully keeps business-logic agnostic; concrete strategies are
    10→ * late-bound to support online A/B testing and hot-swaps without broker restarts.
    11→ *
    12→ * Author: AgoraPulse Engineering
    13→ * License: MIT
    14→ */
    15→
    16→import { Kafka, logLevel } from 'kafkajs';
    17→import { Subject, timer, from } from 'rxjs';
    18→import {
    19→    catchError,
    20→    filter,
    21→    map,
    22→    mergeMap,
    23→    retryWhen,
    24→    tap,
    25→    timeout as rxTimeout,
    26→} from 'rxjs/operators';
    27→import Ajv from 'ajv';
    28→import { readFile } from 'fs/promises';
    29→import { join as joinPath } from 'path';
    30→import pino from 'pino';
    31→
    32→/* -------------------------------------------------------------------------- */
    33→/* Configuration & logger                                                     */
    34→/* -------------------------------------------------------------------------- */
    35→
    36→const DEFAULT_CONSUMER_CONFIG = {
    37→    clientId: 'agorapulse-realtime-consumer',
    38→    brokers: ['localhost:9092'],
    39→    groupId: 'agorapulse-realtime-group',
    40→    topics: ['domain-events'],
    41→    maxBytesPerPartition: 5242880, // 5 MB
    42→};
    43→
    44→const DEFAULT_PRODUCER_CONFIG = {
    45→    clientId: 'agorapulse-feature-producer',
    46→    brokers: ['localhost:9092'],
    47→    topic: 'feature-events',
    48→};
    49→
    50→const log = pino({ name: 'module_21' });
    51→
    52→/* -------------------------------------------------------------------------- */
    53→/* DomainEventStream: Kafka => RxJS Subject                                   */
    54→/* -------------------------------------------------------------------------- */
    55→
    56→/**
    57→ * DomainEventStream consumes Kafka topics and exposes a hot Subject emitting
    58→ * validated domain events.
    59→ */
    60→export class DomainEventStream {
    61→    /**
    62→     * @param {object} config   Consumer configuration
    63→     * @param {object} schema   JSON schema for basic envelope validation
    64→     */
    65→    constructor(config = DEFAULT_CONSUMER_CONFIG, schema) {
    66→        this._config = { ...DEFAULT_CONSUMER_CONFIG, ...config };
    67→        this._kafka = new Kafka({
    68→            clientId: this._config.clientId,
    69→            brokers: this._config.brokers,
    70→            logLevel: logLevel.NOTHING,
    71→        });
    72→
    73→        this._consumer = this._kafka.consumer({ groupId: this._config.groupId });
    74→        this._event$ = new Subject(); // Hot observable for subscribers
    75→
    76→        if (!schema) {
    77→            throw new Error('DomainEventStream requires a validation schema');
    78→        }
    79→        const ajv = new Ajv({ strict: false, removeAdditional: 'failing' });
    80→        this._validator = ajv.compile(schema);
    81→    }
    82→
    83→    /**
    84→     * Hot observable for downstream subscribers
    85→     */
    86→    get stream$() {
    87→        return this._event$.asObservable();
    88→    }
    89→
    90→    /**
    91→     * Connects to Kafka and starts consuming messages.
    92→     */
    93→    async start() {
    94→        await this._consumer.connect();
    95→        for (const topic of this._config.topics) {
    96→            await this._consumer.subscribe({ topic, fromBeginning: false });
    97→        }
    98→
    99→        await this._consumer.run({
   100→            eachMessage: async ({ topic, message }) => {
   101→                try {
   102→                    const payload = JSON.parse(message.value.toString());
   103→                    if (this._validator(payload)) {
   104→                        this._event$.next({ topic, partition: message.partition, payload });
   105→                    } else {
   106→                        log.warn(
   107→                            { errors: this._validator.errors, payload },
   108→                            'Schema validation failed'
   109→                        );
   110→                    }
   111→                } catch (err) {
   112→                    log.error({ err }, 'Failed to deserialize message');
   113→                }
   114→            },
   115→        });
   116→
   117→        log.info('DomainEventStream started');
   118→    }
   119→
   120→    /**
   121→     * Graceful shutdown.
   122→     */
   123→    async stop() {
   124→        await this._consumer.disconnect().catch((e) => log.error(e, 'Error disconnecting'));
   125→        // Complete observable so that downstream can dispose
   126→        this._event$.complete();
   127→        log.info('DomainEventStream stopped');
   128→    }
   129→}
   130→
   131→/* -------------------------------------------------------------------------- */
   132→/* Feature Strategy interface + dynamic loader                                */
   133→/* -------------------------------------------------------------------------- */
   134→
   135→/**
   136→ * Abstract base class for feature engineering strategies.
   137→ * Concrete implementations must implement `extract(event)`.
   138→ */
   139→export class FeatureStrategy {
   140→    /**
   141→     * @param {object} event - validated domain event
   142→     * @returns {Promise<object>} feature object (resolved)
   143→     */
   144→    // eslint-disable-next-line class-methods-use-this, no-unused-vars
   145→    async extract(event) {
   146→        throw new Error('FeatureStrategy.extract() must be implemented');
   147→    }
   148→}
   149→
   150→/**
   151→ * Dynamically loads strategy modules discovered in the provided directory.
   152→ * Each file must export either:
   153→ *  - default class extending FeatureStrategy
   154→ *  - named class 'Strategy' extending FeatureStrategy
   155→ *
   156→ * @param {string} directory absolute path
   157→ * @returns {Promise<Map<string, FeatureStrategy>>} map eventType -> strategy
   158→ */
   159→export async function loadStrategies(directory) {
   160→    const entries = await readFile(joinPath(directory, 'manifest.json'), 'utf8').catch((err) => {
   161→        throw new Error(`Unable to read strategy manifest: ${err.message}`);
   162→    });
   163→
   164→    const manifest = JSON.parse(entries);
   165→    const strategies = new Map();
   166→
   167→    await Promise.all(
   168→        manifest.map(async ({ eventType, module }) => {
   169→            try {
   170→                /* eslint-disable import/no-dynamic-require, global-require */
   171→                const imported = await import(joinPath(directory, module));
   172→                const StrategyClass =
   173→                    imported.default || imported.Strategy || Object.values(imported)[0];
   174→                const instance = new StrategyClass();
   175→
   176→                if (!(instance instanceof FeatureStrategy)) {
   177→                    throw new Error(`Module ${module} does not export a FeatureStrategy`);
   178→                }
   179→                strategies.set(eventType, instance);
   180→            } catch (err) {
   181→                log.error({ err, module }, 'Failed to load strategy');
   182→            }
   183→        })
   184→    );
   185→
   186→    return strategies;
   187→}
   188→
   189→/* -------------------------------------------------------------------------- */
   190→/* FeatureEngineeringPipeline                                                 */
   191→/* -------------------------------------------------------------------------- */
   192→
   193→export class FeatureEngineeringPipeline {
   194→    /**
   195→     * @param {Map<string, FeatureStrategy>} strategies
   196→     * @param {object} producerConfig  Kafka producer configuration
   197→     */
   198→    constructor(strategies, producerConfig = DEFAULT_PRODUCER_CONFIG) {
   199→        this._strategies = strategies;
   200→        this._producerConfig = { ...DEFAULT_PRODUCER_CONFIG, ...producerConfig };
   201→
   202→        // Producer is lazy-connected on first usage
   203→        this._kafka = new Kafka({
   204→            clientId: this._producerConfig.clientId,
   205→            brokers: this._producerConfig.brokers,
   206→            logLevel: logLevel.NOTHING,
   207→        });
   208→        this._producer = this._kafka.producer();
   209→        this._connected = false;
   210→    }
   211→
   212→    /**
   213→     * Attaches the pipeline to the DomainEventStream.
   214→     * @param {DomainEventStream} eventStream
   215→     * @returns {import('rxjs').Subscription}
   216→     */
   217→    attach(eventStream) {
   218→        const PIPELINE_TIMEOUT_MS = 15_000;
   219→
   220→        return eventStream.stream$
   221→            .pipe(
   222→                filter(({ payload }) => this._strategies.has(payload.eventType)),
   223→
   224→                mergeMap(({ payload }) => {
   225→                    const strategy = this._strategies.get(payload.eventType);
   226→                    return from(strategy.extract(payload)).pipe(
   227→                        map((features) => ({
   228→                            key: payload.entityId ?? 'unknown',
   229→                            eventType: payload.eventType,
   230→                            timestamp: Date.now(),
   231→                            features,
   232→                        })),
   233→                        rxTimeout(PIPELINE_TIMEOUT_MS),
   234→                        retryWhen((errors) =>
   235→                            errors.pipe(
   236→                                tap((err) => log.warn({ err }, 'Retrying feature extraction')),
   237→                                // Exponential backoff: wait 1s, 2s, 4s ...
   238→                                mergeMap((err, i) => timer(Math.min(2 ** i * 1_000, 30_000)))
   239→                            )
   240→                        ),
   241→                        catchError((err) => {
   242→                            log.error({ err }, 'Giving up on feature extraction');
   243→                            return []; // swallow & continue
   244→                        })
   245→                    );
   246→                }),
   247→                mergeMap((featureEvent) => this._emitFeatureEvent(featureEvent))
   248→            )
   249→            .subscribe({
   250→                error: (err) => log.error({ err }, 'Pipeline error'),
   251→                complete: () => log.info('FeatureEngineeringPipeline completed'),
   252→            });
   253→    }
   254→
   255→    /* ---------------------------------------------------------------------- */
   256→    /* Internal helpers                                                       */
   257→    /* ---------------------------------------------------------------------- */
   258→
   259→    async _emitFeatureEvent(featureEvent) {
   260→        if (!this._connected) {
   261→            await this._producer.connect();
   262→            this._connected = true;
   263→        }
   264→
   265→        await this._producer
   266→            .send({
   267→                topic: this._producerConfig.topic,
   268→                messages: [
   269→                    {
   270→                        key: featureEvent.key,
   271→                        value: JSON.stringify(featureEvent),
   272→                        timestamp: `${featureEvent.timestamp}`,
   273→                    },
   274→                ],
   275→            })
   276→            .catch((err) => log.error({ err }, 'Failed to send feature event'));
   277→    }
   278→
   279→    async shutdown() {
   280→        if (this._connected) {
   281→            await this._producer.disconnect().catch((err) => log.error(err, 'Producer disconnect'));
   282→            this._connected = false;
   283→        }
   284→    }
   285→}
   286→
   287→/* -------------------------------------------------------------------------- */
   288→/* Bootstrap helper                                                           */
   289→/* -------------------------------------------------------------------------- */
   290→
   291→/**
   292→ * Kicks off the entire ingestion + pipeline with provided configs.
   293→ *
   294→ * @param {object} opts
   295→ * @param {string} opts.strategyDir absolute path where strategies + manifest live
   296→ * @param {object} [opts.consumerConfig] kafka consumer overrides
   297→ * @param {object} [opts.producerConfig] kafka producer overrides
   298→ * @param {object} [opts.schema] JSON schema used for envelope validation
   299→ *
   300→ * @returns {Promise<{shutdown: Function}>} handle to gracefully shutdown
   301→ */
   302→export async function bootstrap(opts) {
   303→    const {
   304→        strategyDir,
   305→        consumerConfig = {},
   306→        producerConfig = {},
   307→        schema = DEFAULT_ENVELOPE_SCHEMA,
   308→    } = opts;
   309→
   310→    const strategies = await loadStrategies(strategyDir);
   311→    log.info({ count: strategies.size }, 'Strategies loaded');
   312→
   313→    const des = new DomainEventStream(consumerConfig, schema);
   314→    const pipeline = new FeatureEngineeringPipeline(strategies, producerConfig);
   315→    const subscription = pipeline.attach(des);
   316→
   317→    await des.start();
   318→
   319→    async function shutdown() {
   320→        log.info('Shutting down...');
   321→        subscription.unsubscribe();
   322→        await pipeline.shutdown();
   323→        await des.stop();
   324→        log.info('Goodbye 👋');
   325→    }
   326→
   327→    return { shutdown };
   328→}
   329→
   330→/* -------------------------------------------------------------------------- */
   331→/* Default JSON-schema for domain-event envelope                              */
   332→/* -------------------------------------------------------------------------- */
   333→
   334→export const DEFAULT_ENVELOPE_SCHEMA = {
   335→    $id: 'https://agorapulse.ai/schemas/domainEventEnvelope.json',
   336→    type: 'object',
   337→    required: ['eventId', 'eventType', 'entityId', 'payload', 'createdAt'],
   338→    additionalProperties: false,
   339→    properties: {
   340→        eventId: { type: 'string', format: 'uuid' },
   341→        eventType: { type: 'string' },
   342→        entityId: { type: 'string' },
   343→        createdAt: { type: 'string', format: 'date-time' },
   344→        payload: { type: 'object' },
   345→    },
   346→};
   347→
   348→/* -------------------------------------------------------------------------- */
   349→/* If executed directly: invoke bootstrap with defaults                       */
   350→/* -------------------------------------------------------------------------- */
   351→
   352→if (import.meta.url === `file://${process.argv[1]}`) {
   353→    // eslint-disable-next-line unicorn/prefer-top-level-await
   354→    bootstrap({
   355→        strategyDir: joinPath(process.cwd(), 'strategies'),
   356→    }).catch((err) => {
   357→        log.fatal({ err }, 'Fatal error during bootstrap');
   358→        process.exit(1);
   359→    });
   360→}
