     2→/**
     3→ * src/utils.js
     4→ *
     5→ * A curated set of general-purpose utilities shared by multiple services
     6→ * inside the AgoraPulse monorepo. These helpers are intentionally dependency-
     7→ * light and focus on the runtime characteristics required by distributed,
     8→ * event-driven systems (retry, backoff, timeout, etc.).
     9→ *
    10→ * NOTE: This file is pure-E SM (uses `import`/`export`). Ensure `"type":"module"`
    11→ * is set in the nearest package.json or transpile appropriately.
    12→ */
    13→
    14→import crypto from 'crypto';
    15→import fs from 'fs/promises';
    16→import path from 'path';
    17→import process from 'process';
    18→import { setTimeout as sleep } from 'timers/promises';
    19→
    20→import pino from 'pino';
    21→import debugFactory from 'debug';
    22→import JSONbig from 'json-bigint';
    23→
    24→// ---------------------------------------------------------------------------
    25→// Logging helpers
    26→// ---------------------------------------------------------------------------
    27→
    28→/**
    29→ * Shared pino logger instance.  Each consumer can create a child logger via
    30→ * `logger.child({ module: 'xyz' })` to append contextual metadata.
    31→ */
    32→export const logger = pino({
    33→  name: 'agorapulse-utils',
    34→  level: process.env.LOG_LEVEL || 'info',
    35→  redact: ['password', 'apiKey', 'token'],
    36→});
    37→
    38→/** Lightweight, low-overhead debug logs (`DEBUG=*` env flag required). */
    39→export const debug = debugFactory('agorapulse:*');
    40→
    41→// ---------------------------------------------------------------------------
    42→// Environment variable helpers
    43→// ---------------------------------------------------------------------------
    44→
    45→/**
    46→ * Fetch and coercively validate an environment variable.
    47→ *
    48→ * @template T
    49→ * @param {string} key                - Name of the env var.
    50→ * @param {Object} [opts]
    51→ * @param {boolean} [opts.required]   - Throw if the variable is empty.
    52→ * @param {'string'|'number'|'boolean'|'json'} [opts.type] - Desired coercion.
    53→ * @param {T} [opts.default]          - Fallback value if env var is undefined.
    54→ * @returns {T}
    55→ */
    56→export function getEnv(key, opts = {}) {
    57→  const {
    58→    required = false,
    59→    type = 'string',
    60→    default: defaultValue,
    61→  } = opts;
    62→
    63→  let raw = process.env[key];
    64→
    65→  if (raw == null || raw === '') {
    66→    if (required && defaultValue === undefined) {
    67→      throw new Error(`Missing required environment variable ${key}`);
    68→    }
    69→    raw = defaultValue;
    70→  }
    71→
    72→  if (raw == null) return raw;
    73→
    74→  try {
    75→    switch (type) {
    76→      case 'number': {
    77→        const num = Number(raw);
    78→        if (Number.isNaN(num)) throw new Error();
    79→        return num;
    80→      }
    81→      case 'boolean':
    82→        return raw === 'true' || raw === true;
    83→      case 'json':
    84→        return JSONbig.parse(raw);
    85→      case 'string':
    86→      default:
    87→        return String(raw);
    88→    }
    89→  } catch {
    90→    throw new Error(`Unable to coerce env var "${key}" to type "${type}"`);
    91→  }
    92→}
    93→
    94→// ---------------------------------------------------------------------------
    95→// Deterministic object/hash helpers
    96→// ---------------------------------------------------------------------------
    97→
    98→/**
    99→ * Create a deterministic JSON string that is stable across key order.
   100→ * Useful for hashing objects so that logically identical objects
   101→ * produce identical digests.
   102→ *
   103→ * @param {unknown} obj
   104→ * @returns {string}
   105→ */
   106→export function stableStringify(obj) {
   107→  const seen = new WeakSet();
   108→  const replacer = (_k, value) => {
   109→    if (typeof value === 'object' && value !== null) {
   110→      if (seen.has(value)) return '[Circular]';
   111→      seen.add(value);
   112→
   113→      // Sort object keys recursively.
   114→      if (!Array.isArray(value)) {
   115→        return Object.keys(value)
   116→          .sort()
   117→          .reduce((acc, key) => {
   118→            acc[key] = value[key];
   119→            return acc;
   120→          }, {});
   121→      }
   122→    }
   123→    return value;
   124→  };
   125→
   126→  return JSONbig.stringify(obj, replacer);
   127→}
   128→
   129→/**
   130→ * Return a crypto hash (hex string) of any serializable object.
   131→ *
   132→ * @param {unknown} obj
   133→ * @param {string} [algo='sha256']
   134→ * @returns {string}
   135→ */
   136→export function hashObject(obj, algo = 'sha256') {
   137→  const str = stableStringify(obj);
   138→  return crypto.createHash(algo).update(str).digest('hex');
   139→}
   140→
   141→// ---------------------------------------------------------------------------
   142→// Async control flow
   143→// ---------------------------------------------------------------------------
   144→
   145→/**
   146→ * Sleep/delay helper that automatically converts seconds if a non-integer
   147→ * is provided (e.g. `sleepSec(0.2)`).
   148→ *
   149→ * @param {number} ms Milliseconds to wait.
   150→ */
   151→export const delay = (ms) => sleep(ms);
   152→
   153→/**
   154→ * Promise wrapper that adds a timeout race.
   155→ *
   156→ * @template T
   157→ * @param {Promise<T>} promise
   158→ * @param {number} ms                     - Timeout in milliseconds.
   159→ * @param {string} [message='Operation timed out']
   160→ * @returns {Promise<T>}
   161→ */
   162→export function withTimeout(promise, ms, message = 'Operation timed out') {
   163→  return Promise.race([
   164→    promise,
   165→    sleep(ms).then(() => {
   166→      const err = new Error(message);
   167→      err.code = 'ETIMEDOUT';
   168→      throw err;
   169→    }),
   170→  ]);
   171→}
