   173→/**
   174→ * Generic async retry with exponential backoff & full jitter.
   175→ *
   176→ * @template T
   177→ * @param {() => Promise<T>} fn
   178→ * @param {Object} [opts]
   179→ * @param {number} [opts.retries=5]        - Total attempts (includes first).
   180→ * @param {number} [opts.min=100]          - Minimum delay (ms).
   181→ * @param {number} [opts.factor=2]         - Exponential factor.
   182→ * @param {number} [opts.max=15_000]       - Maximum delay (ms).
   183→ * @param {(err: any) => boolean} [opts.shouldRetry] - Decide whether to retry.
   184→ * @param {import('pino').Logger} [opts.logger]       - Logger for warnings.
   185→ * @returns {Promise<T>}
   186→ */
   187→export async function retry(fn, opts = {}) {
   188→  const {
   189→    retries = 5,
   190→    min = 100,
   191→    factor = 2,
   192→    max = 15_000,
   193→    shouldRetry = () => true,
   194→    logger: log = logger,
   195→  } = opts;
   196→
   197→  let attempt = 0;
   198→
   199→  // eslint-disable-next-line no-constant-condition
   200→  while (true) {
   201→    try {
   202→      return await fn();
   203→    } catch (err) {
   204→      attempt += 1;
   205→      if (attempt >= retries || !shouldRetry(err)) {
   206→        throw err;
   207→      }
   208→
   209→      const backoff = Math.min(max, Math.round(min * factor ** attempt));
   210→      // Full jitter (AWS-style)
   211→      const delayMs = Math.random() * backoff;
   212→
   213→      log.warn(
   214→        {
   215→          err,
   216→          attempt,
   217→          delay: Math.round(delayMs),
   218→        },
   219→        'Retrying operation',
   220→      );
   221→
   222→      await sleep(delayMs);
   223→    }
   224→  }
   225→}
