    19→ *     kafka: { brokers: ['kafka-broker:9092'], clientId: 'agorapulse-router' },
    20→ *     topics: ['social.raw'],
    21→ *     strategies: {
    22→ *       tweet_created: new TweetCreatedStrategy(),
    23→ *       reaction_added: new ReactionAddedStrategy()
    24→ *     }
    25→ *   });
    26→ *
    27→ *   router.events$.subscribe(event => {
    28→ *     // push to feature engineering pipeline, etc.
    29→ *   });
