    33→
    34→'use strict';
    35→
    36→const { Kafka, logLevel: KafkaLogLevel } = require('kafkajs');
    37→const { Subject, of, throwError } = require('rxjs');
    38→const { retryWhen, mergeMap, delay } = require('rxjs/operators');
    39→const winston = require('winston');
    40→const promClient = require('prom-client');
    41→
    42→/* -------------------------------------------------------------------------- */
    43→/*                               Configuration                                */
    44→/* -------------------------------------------------------------------------- */
    45→
    46→/**
    47→ * Default maximum number of retry attempts for transient failures.
    48→ * Exposed for test injection / tuning from the outside.
    49→ */
    50→const DEFAULT_MAX_RETRIES = 5;
    51→
    52→/**
