    58→  return winston.createLogger({
    59→    level: process.env.LOG_LEVEL || 'info',
    60→    defaultMeta: { scope },
    61→    format: winston.format.combine(
    62→      winston.format.timestamp(),
    63→      winston.format.json()
    64→    ),
    65→    transports: [new winston.transports.Console()]
    66→  });
    67→}
    68→
    69→/* -------------------------------------------------------------------------- */
    70→/*                         Prometheus Metric Registry                         */
    71→/* -------------------------------------------------------------------------- */
    72→
    73→const METRIC_PREFIX = 'agorapulse_router_';
