     2→/**
     3→ * src/module_35.js
     4→ *
     5→ * KafkaRxBridge
     6→ * -------------
     7→ * A thin but powerful wrapper that turns Kafka topics into RxJS observables
     8→ * and vice-versa.  Used by the event-driven core to fan-out domain events
     9→ * through both Kafka and RxJS with unified back-pressure semantics.
    10→ *
    11→ * Production-grade features included:
    12→ *  • Automatic reconnects with exponential back-off
    13→ *  • Graceful shutdown hooks
    14→ *  • Prometheus metrics
    15→ *  • Pluggable serializers / deserializers
    16→ *  • Type-safe (via JSDoc) message envelopes
    17→ *
    18→ * NOTE: This file is written in modern ES2022 JavaScript; consumers can compile
    19→ *       down to earlier versions through Babel if necessary.
    20→ */
    21→
    22→import { Kafka, logLevel } from 'kafkajs';
    23→import { Observable, Subject } from 'rxjs';
    24→import { tap, finalize } from 'rxjs/operators';
    25→import pRetry from 'p-retry';
    26→import pino from 'pino';
    27→import * as promClient from 'prom-client';
    28→
    29→// ---------------------------------------------------------------------------
    30→// Configuration helpers
    31→// ---------------------------------------------------------------------------
    32→
    33→const {
    34→  KAFKA_BROKERS = '',
    35→  KAFKA_CLIENT_ID = 'agora-pulse-core',
    36→  KAFKA_LOG_LEVEL = 'WARN',
    37→  KAFKA_DEFAULT_GROUP_ID = 'agora-pulse-pipeline',
    38→} = process.env;
    39→
    40→const toKafkaLogLevel = (lvl) =>
    41→  ({
    42→    TRACE: logLevel.DEBUG,
    43→    DEBUG: logLevel.DEBUG,
    44→    INFO: logLevel.INFO,
    45→    WARN: logLevel.WARN,
    46→    ERROR: logLevel.ERROR,
    47→  }[lvl.toUpperCase()] ?? logLevel.WARN);
    48→
    49→// ---------------------------------------------------------------------------
    50→// Logger
    51→// ---------------------------------------------------------------------------
    52→
    53→const logger = pino({
    54→  name: 'KafkaRxBridge',
    55→  level: (process.env.LOG_LEVEL || 'info').toLowerCase(),
    56→});
    57→
    58→// ---------------------------------------------------------------------------
    59→// Metrics
    60→// ---------------------------------------------------------------------------
    61→
    62→const metrics = {
    63→  messagesConsumed: new promClient.Counter({
    64→    name: 'agorapulse_kafka_messages_consumed_total',
    65→    help: 'Total number of messages consumed by KafkaRxBridge',
    66→    labelNames: ['topic'],
    67→  }),
    68→  messagesProduced: new promClient.Counter({
    69→    name: 'agorapulse_kafka_messages_produced_total',
    70→    help: 'Total number of messages produced by KafkaRxBridge',
    71→    labelNames: ['topic'],
    72→  }),
    73→  consumerLag: new promClient.Gauge({
    74→    name: 'agorapulse_kafka_consumer_lag',
    75→    help: 'Current consumer lag (high watermark offset - committed)',
    76→    labelNames: ['topic', 'partition'],
    77→  }),
    78→};
    79→
    80→// ---------------------------------------------------------------------------
    81→// Default (de)serializers – can be overridden per-method call
    82→// ---------------------------------------------------------------------------
    83→
    84→const defaultSerializer = (data) => Buffer.from(JSON.stringify(data));
    85→const defaultDeserializer = (buf) => JSON.parse(buf.toString());
    86→
    87→// ---------------------------------------------------------------------------
    88→// KafkaRxBridge implementation
    89→// ---------------------------------------------------------------------------
    90→
    91→export class KafkaRxBridge {
    92→  /**
    93→   * @param {Object} [options]
    94→   * @param {string[]} [options.brokers]
    95→   * @param {string}   [options.clientId]
    96→   * @param {logLevel} [options.logLevel]
    97→   */
    98→  constructor({
    99→    brokers = KAFKA_BROKERS.split(',').filter(Boolean),
   100→    clientId = KAFKA_CLIENT_ID,
   101→    logLevel = toKafkaLogLevel(KAFKA_LOG_LEVEL),
   102→  } = {}) {
   103→    if (!brokers.length) {
   104→      throw new Error(
   105→        'KafkaRxBridge: At least one broker address must be provided in env KAFKA_BROKERS or constructor options',
   106→      );
   107→    }
   108→
   109→    this.kafka = new Kafka({ brokers, clientId, logLevel });
   110→    this._subscriptions = new Set(); // Track active consumers for shutdown
   111→    logger.info({ brokers, clientId }, 'KafkaRxBridge initialized');
   112→  }
   113→
   114→  /**
   115→   * Turns a Kafka topic into an RxJS Observable stream.
   116→   *
   117→   * @template T
   118→   * @param {string|string[]} topics
   119→   * @param {Object} [opts]
   120→   * @param {string}  [opts.groupId]                    Consumer group id
   121→   * @param {number}  [opts.maxBytesPerPartition=1048576]
   122→   * @param {Function} [opts.deserializer]              (msg.value) => T
   123→   * @param {boolean} [opts.autoCommit=true]            Auto-commit after nextTick
   124→   * @returns {Observable<{value: T, topic: string, partition: number, offset: string}>}
   125→   */
   126→  createTopicObservable(
   127→    topics,
   128→    {
   129→      groupId = KAFKA_DEFAULT_GROUP_ID,
   130→      maxBytesPerPartition = 1_048_576,
   131→      deserializer = defaultDeserializer,
   132→      autoCommit = true,
   133→    } = {},
   134→  ) {
   135→    const topicList = Array.isArray(topics) ? topics : [topics];
   136→    const subject = new Subject();
   137→
   138→    const consumer = this.kafka.consumer({ groupId, maxBytesPerPartition });
   139→    this._subscriptions.add(consumer);
   140→
   141→    const connectAndRun = async () => {
   142→      await consumer.connect();
   143→      for (const topic of topicList) {
   144→        await consumer.subscribe({ topic, fromBeginning: false });
   145→      }
   146→
   147→      await consumer.run({
   148→        eachMessage: async ({ topic, partition, message, heartbeat, commitOffsetsIfNecessary }) => {
   149→          try {
   150→            metrics.messagesConsumed.inc({ topic });
   151→            const deserialized = deserializer(message.value);
   152→            const payload = { value: deserialized, topic, partition, offset: message.offset };
   153→
   154→            // Push downstream
   155→            subject.next(payload);
   156→
   157→            // Back-pressure: wait until next micro-task tick to commit to allow
   158→            // synchronous observers to throw (so we can gracefully stop)
   159→            if (autoCommit) {
   160→              setImmediate(async () => {
   161→                try {
   162→                  await commitOffsetsIfNecessary();
   163→                  await heartbeat();
   164→                } catch (err) {
   165→                  logger.warn({ err }, 'Commit / heartbeat failed');
   166→                }
   167→              });
   168→            }
   169→          } catch (err) {
   170→            logger.error({ err }, 'Failed to process message – closing observable');
   171→            subject.error(err);
   172→          }
   173→        },
   174→      });
   175→    };
   176→
   177→    // Attach retry logic
   178→    pRetry(connectAndRun, {
   179→      forever: true,
   180→      onFailedAttempt: (err) =>
   181→        logger.warn(
   182→          { attempt: err.attemptNumber, retriesLeft: err.retriesLeft, err },
   183→          'Kafka consumer failed – retrying',
   184→        ),
   185→    }).catch((err) => {
   186→      // This should never happen because forever: true, but guard anyway
   187→      subject.error(err);
   188→    });
   189→
   190→    const observable = subject.asObservable().pipe(
   191→      tap(({ topic, partition, offset }) => {
   192→        metrics.consumerLag.set({ topic, partition }, Number(offset));
   193→      }),
   194→      finalize(async () => {
   195→        logger.info({ topics: topicList }, 'Observable finalizing – disconnecting consumer');
   196→        try {
   197→          await consumer.disconnect();
   198→        } catch (err) {
   199→          logger.warn({ err }, 'Error disconnecting consumer');
   200→        } finally {
   201→          this._subscriptions.delete(consumer);
   202→        }
   203→      }),
   204→    );
   205→
   206→    return observable;
   207→  }
   208→
   209→  /**
   210→   * Pushes an RxJS or AsyncIterable stream into a Kafka topic.
   211→   *
   212→   * @template T
   213→   * @param {Observable<T>|AsyncIterable<T>} stream
   214→   * @param {string} topic
   215→   * @param {Object} [opts]
   216→   * @param {Function} [opts.serializer] (data: T) => Buffer
   217→   * @param {number}   [opts.batchSize=100]
   218→   * @returns {Promise<void>}
   219→   */
   220→  async produceFromStream(
   221→    stream,
   222→    topic,
   223→    { serializer = defaultSerializer, batchSize = 100 } = {},
   224→  ) {
   225→    const producer = this.kafka.producer();
   226→    await producer.connect();
   227→    logger.info({ topic }, 'Kafka producer connected');
   228→
   229→    const sendBatch = async (messages) => {
   230→      if (!messages.length) return;
   231→      await producer.send({ topic, messages });
   232→      messages.forEach(() => metrics.messagesProduced.inc({ topic }));
   233→    };
   234→
   235→    const buffer = [];
   236→    const flushIfNeeded = async () => {
   237→      if (buffer.length >= batchSize) {
   238→        await sendBatch(buffer.splice(0, buffer.length));
   239→      }
   240→    };
   241→
   242→    const finalize = async () => {
   243→      await sendBatch(buffer);
   244→      await producer.disconnect();
   245→      logger.info({ topic }, 'Kafka producer disconnected');
   246→    };
   247→
   248→    // Stream may be an RxJS observable or AsyncIterable
   249→    const asyncIter = typeof stream[Symbol.asyncIterator] === 'function'
   250→      ? stream[Symbol.asyncIterator]()
   251→      : stream[Symbol.iterator] // RxJS observable
   252→        ? (async function* () {
   253→            let done = false;
   254→            const sub = stream.subscribe({
   255→              next: (val) => buffer.push({ value: serializer(val) }),
   256→              error: async (err) => {
   257→                logger.error({ err }, 'Stream error – terminating producer');
   258→                done = true;
   259→                await finalize();
   260→              },
   261→              complete: async () => {
   262→                done = true;
   263→                await finalize();
   264→              },
   265→            });
   266→
   267→            while (!done) {
   268→              await flushIfNeeded();
   269→              await new Promise((r) => setTimeout(r, 10));
   270→            }
   271→            sub.unsubscribe();
   272→          })()
   273→        : null;
   274→
   275→    if (!asyncIter) {
   276→      throw new Error('Unsupported stream type. Provide Observable or AsyncIterable.');
   277→    }
   278→
   279→    for await (const data of asyncIter) {
   280→      if (data != null) buffer.push({ value: serializer(data) });
   281→      await flushIfNeeded();
   282→    }
   283→
   284→    await finalize();
   285→  }
   286→
   287→  // -------------------------------------------------------------------------
   288→  // Graceful shutdown helpers
   289→  // -------------------------------------------------------------------------
   290→
   291→  /**
   292→   * Disconnects all active consumers/producers managed by this bridge.
   293→   * Should be called on application shutdown.
   294→   */
   295→  async close() {
   296→    logger.info('Closing KafkaRxBridge…');
   297→    await Promise.all(
   298→      [...this._subscriptions].map((sub) =>
   299→        sub
   300→          .disconnect()
   301→          .catch((err) => logger.warn({ err }, 'Failed to disconnect consumer')),
   302→      ),
   303→    );
   304→    this._subscriptions.clear();
   305→    logger.info('KafkaRxBridge closed');
   306→  }
   307→}
   308→
   309→// ---------------------------------------------------------------------------
   310→// Process signal handling
   311→// ---------------------------------------------------------------------------
   312→
   313→/* c8 ignore start */
   314→const bridges = new Set();
   315→export const registerBridgeInstance = (bridge) => bridges.add(bridge);
   316→
   317→const handleTerminationSignal = async (signal) => {
   318→  logger.info({ signal }, 'Received termination signal – shutting down bridges');
   319→  await Promise.all([...bridges].map((b) => b.close()));
   320→  process.exit(0);
   321→};
   322→
   323→process.once('SIGTERM', handleTerminationSignal);
   324→process.once('SIGINT', handleTerminationSignal);
   325→/* c8 ignore end */
   326→```

