1→/**
     2→ * AgoraPulse: Real-Time Social Signal Intelligence
     3→ * ------------------------------------------------
     4→ * Module: SentimentShiftSentinel
     5→ *
     6→ * src/module_13.js
     7→ *
     8→ * This module listens to the streaming sentiment-analysis output coming from the
     9→ * model-serving layer (Kafka topic: `model.sentiment.v1`).  It computes a
    10→ * rolling baseline and emits a domain event whenever the current sentiment
    11→ * diverges from the baseline beyond a configurable threshold.  The threshold
    12→ * calculation is pluggable (Strategy Pattern) so that different teams can swap
    13→ * in their own logic without touching the sentinel core.
    14→ *
    15→ * Typical downstream listeners:
    16→ *   • Moderation Service – auto-flag potential raids / toxicity spikes
    17→ *   • Experiment Tracker – correlate sentiment drift with model versions
    18→ *   • Auto-Retraining Orchestrator – schedule rapid fine-tune runs
    19→ *
    20→ * The module is written in vanilla Node.js (CommonJS) to keep the core runtime
    21→ * dependencies minimal and interoperable with the rest of the platform.
    22→ *
    23→ * ------------------------------------------------
    24→ * NOTE: This file purposefully avoids any project-private imports so that it
    25→ * can be copy-pasted for review.  Replace the placeholder paths (`@agora/*`)
    26→ * with the actual local packages when integrating into the monorepo.
    27→ */
    28→
    29→"use strict";
    30→
    31→/* ────────────────────────────────────────────────────────────────────
    32→ * External Dependencies
    33→ * ──────────────────────────────────────────────────────────────────── */
    34→const { Kafka }               = require("kafkajs");
    35→const { EventEmitter }        = require("events");
    36→const { Subject, from }       = require("rxjs");
    37→const {
    38→    bufferTime,
    39→    filter,
    40→    tap,
    41→    mergeMap,
    42→    catchError,
    43→}                              = require("rxjs/operators");
    44→const pino                    = require("pino");
    45→
    46→/* ────────────────────────────────────────────────────────────────────
    47→ * Internal / Project Dependencies (replace with real paths)
    48→ * ──────────────────────────────────────────────────────────────────── */
    49→// const { DomainEvent }      = require("@agora/events");
    50→// const { emitEvent }        = require("@agora/event-bus");
    51→
    52→/* ────────────────────────────────────────────────────────────────────
    53→ * Constants
    54→ * ──────────────────────────────────────────────────────────────────── */
    55→const DEFAULT_KAFKA_BROKERS = process.env.KAFKA_BROKERS?.split(",") || [
    56→    "localhost:9092",
    57→];
    58→const SENTIMENT_TOPIC       = process.env.SENTIMENT_TOPIC || "model.sentiment.v1";
    59→const LOGGER                = pino({ name: "SentimentShiftSentinel" });
    60→
    61→/* ────────────────────────────────────────────────────────────────────
    62→ * Helper: Exponential Moving Average
    63→ * ──────────────────────────────────────────────────────────────────── */
    64→function ewma(prev, curr, alpha) {
    65→    return prev == null ? curr : alpha * curr + (1 - alpha) * prev;
    66→}
    67→
    68→/* ────────────────────────────────────────────────────────────────────
    69→ * Strategy Pattern: Threshold Calculation
    70→ * ──────────────────────────────────────────────────────────────────── */
    71→
    72→/**
    73→ * @typedef {Object} StrategyContext
    74→ * @property {number[]} windowValues – Sentiment scores inside the window
    75→ * @property {number}   globalBaseline – Previously learned global baseline
    76→ */
    77→
    78→/**
    79→ * BaseStrategy (non-instantiable)
    80→ */
    81→class BaseStrategy {
    82→    /**
    83→     * @param {Object} opts
    84→     * @param {number} opts.alpha – Smoothing factor (0 < alpha ≤ 1)
    85→     * @param {number} opts.k – Multiplier for standard deviation
    86→     */
    87→    constructor(opts = {}) {
    88→        if (new.target === BaseStrategy) {
    89→            throw new TypeError("Cannot instantiate abstract BaseStrategy");
    90→        }
    91→        this.alpha    = opts.alpha ?? 0.3;
    92→        this.k        = opts.k     ?? 2.0;
    93→        this.baseline = null;       // EWMA baseline
    94→    }
    95→
    96→    /**
    97→     * @param {StrategyContext} ctx
    98→     * @returns {{shiftValue: number, isShift: boolean}}
    99→     */
   100→    next(ctx) {
   101→        throw new Error("next() must be implemented by subclasses");
   102→    }
   103→}
   104→
   105→/**
   106→ * StaticThresholdStrategy
   107→ * Uses a fixed absolute threshold.
   108→ */
   109→class StaticThresholdStrategy extends BaseStrategy {
   110→    constructor(threshold = 0.2) {
   111→        super();
   112→        this.threshold = threshold;
   113→    }
   114→
   115→    next({ windowValues }) {
   116→        const currentAvg = mean(windowValues);
   117→        if (this.baseline == null) this.baseline = currentAvg;
   118→
   119→        const shiftValue = currentAvg - this.baseline;
   120→        const isShift    = Math.abs(shiftValue) >= this.threshold;
   121→
   122→        // Keep baseline static – no update
   123→        return { shiftValue, isShift };
   124→    }
   125→}
   126→
   127→/**
   128→ * AdaptiveThresholdStrategy
   129→ * Baseline & threshold adapt over time using EWMA and rolling std-dev.
   130→ */
   131→class AdaptiveThresholdStrategy extends BaseStrategy {
   132→    constructor(opts = {}) {
   133→        super(opts);
   134→        this.stdDev = null;
   135→    }
   136→
   137→    next({ windowValues }) {
   138→        const currentAvg = mean(windowValues);
   139→        // Update baseline with EWMA
   140→        this.baseline = ewma(this.baseline, currentAvg, this.alpha);
   141→        // Update standard deviation (Bessel correction)
   142→        const windowStd = std(windowValues);
   143→        this.stdDev     = ewma(this.stdDev, windowStd, this.alpha);
   144→
   145→        const dynamicThreshold = this.k * (this.stdDev || 0);
   146→        const shiftValue       = currentAvg - this.baseline;
   147→        const isShift          = Math.abs(shiftValue) >= dynamicThreshold;
   148→
   149→        return { shiftValue, isShift };
   150→    }
   151→}
   152→
   153→/* ────────────────────────────────────────────────────────────────────
   154→ * Sentinel Core
   155→ * ──────────────────────────────────────────────────────────────────── */
   156→
   157→/**
